def solve(words: Array[String]): Array[Long] = {
    val n = words.length
    if (n == 1) return Array(0L)

    val answer = new Array[Long](n)

    for (i <- 0 until n) {
        val filtered = words.take(i) ++ words.drop(i + 1)
        var maxLen = 0L

        for (j <- 0 until filtered.length - 1) {
            val s1 = filtered(j)
            val s2 = filtered(j + 1)
            var len = 0
            while (len < s1.length && len < s2.length && s1(len) == s2(len)) {
                len += 1
            }
            if (len > maxLen) {
                maxLen = len
            }
        }

        answer(i) = maxLen
    }

    answer
}
